const rows = $input.all().map(i => i.json);

// Timezone helper
function toNY(d) {
  return new Date(new Date(d).toLocaleString('en-US', {timeZone: 'America/New_York'}));
}

const nowNY = toNY(new Date());
const todayStart = new Date(nowNY);
todayStart.setHours(0,0,0,0);

// Filter today's events
const today = rows.filter(r => {
  const t = toNY(r.logged_at);
  return t >= todayStart;
});

const feedsToday = today.filter(r => r.event_type === 'feed');
const diapersToday = today.filter(r => r.event_type === 'diaper');
const sleepToday = today.filter(r => r.event_type === 'sleep');
const bathsToday = today.filter(r => r.event_type === 'bath');
const medicinesToday = today.filter(r => r.event_type === 'medicine');
const tummyTimesToday = today.filter(r => r.event_type === 'tummy_time');

// Last feed
const lastFeed = rows.find(r => r.event_type === 'feed');
let last_feed_min = null;
let last_feed_type = null;
if (lastFeed) {
  last_feed_min = Math.round((Date.now() - new Date(lastFeed.logged_at).getTime()) / 60000);
  last_feed_type = lastFeed.event_subtype || null;
}

// Last diaper
const lastDiaper = rows.find(r => r.event_type === 'diaper');
let last_diaper_min = null;
let last_diaper_type = null;
if (lastDiaper) {
  last_diaper_min = Math.round((Date.now() - new Date(lastDiaper.logged_at).getTime()) / 60000);
  last_diaper_type = lastDiaper.event_subtype || null;
}

// Sleep analysis
const latestSleep = rows.find(r => r.event_type === 'sleep');
const is_sleeping = latestSleep ? latestSleep.event_subtype === 'start' : false;

// Sleep total today — pair start/end
const sleepEvents = sleepToday.slice().reverse(); // chronological
let sleepMinToday = 0;
let pendingStart = null;
for (const ev of sleepEvents) {
  if (ev.event_subtype === 'start') {
    pendingStart = new Date(ev.logged_at);
  } else if (ev.event_subtype === 'end' && pendingStart) {
    sleepMinToday += (new Date(ev.logged_at).getTime() - pendingStart.getTime()) / 60000;
    pendingStart = null;
  }
}
// If currently sleeping, add time since last start
if (is_sleeping && pendingStart) {
  sleepMinToday += (Date.now() - pendingStart.getTime()) / 60000;
}
sleepMinToday = Math.round(sleepMinToday);
const sleepH = Math.floor(sleepMinToday / 60);
const sleepM = sleepMinToday % 60;
const sleep_total_today = sleepH + 'h ' + sleepM + 'm';

const stats = {
  last_feed_min,
  last_feed_type,
  last_diaper_min,
  last_diaper_type,
  feeds_today: feedsToday.length,
  diapers_today: diapersToday.length,
  sleep_total_today,
  sleep_min_today: sleepMinToday,
  is_sleeping,
  baths_today: bathsToday.length,
  medicines_today: medicinesToday.length,
  tummy_times_today: tummyTimesToday.length,
  pumps_today: today.filter(r => r.event_type === 'pump').length
};

const entries = rows.slice(0, 50).map(r => ({
  id: r.id,
  event_type: r.event_type,
  event_subtype: r.event_subtype,
  note: r.note,
  logged_at: r.logged_at,
  time: r.time
}));

return [{json: {count: rows.length, stats, entries}}];
